import { useState } from "react";
import shop1 from "../assets/shop1.png";
import shop2 from "../assets/shop2.png";
import shop3 from "../assets/shop3.png";

function Projects() {
  const images = [shop1, shop2, shop3];
  const [current, setCurrent] = useState(0);

  const nextSlide = () => {
    setCurrent((current + 1) % images.length);
  };

  const prevSlide = () => {
    setCurrent((current - 1 + images.length) % images.length);
  };

  return (
    <section id="projects" className="section">
      <h2 className="section-title">Projects</h2>

      <div className="project-card">

        {/* Image Slider */}
        <div className="slider">
          <img src={images[current]} alt="Project Screenshot" />

          <button className="prev" onClick={prevSlide}>❮</button>
          <button className="next" onClick={nextSlide}>❯</button>
        </div>

        {/* Content */}
        <div className="project-content">
          <h3>ShopNix E-commerce Website</h3>

          <p>
            Full-stack e-commerce platform featuring authentication,
            cart management, product listing and secure checkout.
          </p>

          <div className="tech-stack">
            <span>React</span>
            <span>Node.js</span>
            <span>Express</span>
            <span>MongoDB</span>
          </div>

          <a
            href="https://shopnix-client.vercel.app"
            target="_blank"
            rel="noreferrer"
            className="btn primary"
          >
            Live Demo
          </a>
        </div>

      </div>
    </section>
  );
}

export default Projects;
